import {
  type ChangeEvent,
  forwardRef,
  type InputHTMLAttributes,
  type ReactNode,
  useCallback,
  useContext,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { CheckboxGroupContext, type CheckboxValueType } from './CheckboxGroup';

export interface CheckboxProps
  extends Omit<
    InputHTMLAttributes<HTMLInputElement>,
    'value' | 'defaultValue' | 'onChange' | 'type' | 'size' | 'children'
  > {
  /** Controlled checked state (standalone). */
  checked?: boolean;
  /** Default checked state when uncontrolled (standalone). */
  defaultChecked?: boolean;
  /** Fired with the next checked state. */
  onChange?: (checked: boolean) => void;
  /** Value used to identify the checkbox inside a CheckboxGroup. */
  value?: CheckboxValueType;
  /** Content; also rendered when no children are provided. */
  label?: ReactNode;
  /** Disable the checkbox. */
  disabled?: boolean;
  /** Render the indeterminate (partial) state. */
  indeterminate?: boolean;
  /** Wrap the checkbox in a bordered box. */
  border?: boolean;
  /** Size. Falls back to the nearest CheckboxGroup / ConfigProvider. */
  size?: ComponentSize;
  /** Native input `name`. */
  name?: string;
  children?: ReactNode;
}

export const Checkbox = forwardRef<HTMLInputElement, CheckboxProps>(function Checkbox(props, ref) {
  const group = useContext(CheckboxGroupContext);
  const {
    checked: checkedProp,
    defaultChecked,
    onChange,
    value,
    label,
    disabled: disabledProp,
    indeterminate = false,
    border = false,
    size: sizeProp,
    name,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('checkbox');
  const size = useSize(sizeProp ?? group?.size);

  const isControlled = checkedProp !== undefined;
  const [internalChecked, setInternalChecked] = useState(defaultChecked ?? false);

  const inGroup = group !== null;
  const checked = inGroup
    ? value !== undefined && group.isChecked(value)
    : isControlled
      ? checkedProp
      : internalChecked;

  const disabled = useDisabled(disabledProp || group?.disabled);

  // In a group, block toggling that would violate min/max limits.
  const limited =
    inGroup &&
    value !== undefined &&
    ((checked && group.min !== undefined && group.value.length <= group.min) ||
      (!checked && group.max !== undefined && group.value.length >= group.max));

  const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
    if (disabled) return;
    const next = event.target.checked;
    if (inGroup) {
      if (value !== undefined) group.toggle(value);
      onChange?.(next);
    } else {
      if (!isControlled) setInternalChecked(next);
      onChange?.(next);
    }
  };

  // The native `indeterminate` flag is a DOM property, not an attribute, so it
  // must be set imperatively. Merge that with the forwarded ref.
  const setRef = useCallback(
    (node: HTMLInputElement | null) => {
      if (node) node.indeterminate = indeterminate;
      if (typeof ref === 'function') ref(node);
      else if (ref) ref.current = node;
    },
    [indeterminate, ref],
  );

  const content = children ?? label;

  // A limit-blocked checkbox is non-interactive, so it must also read as disabled.
  const displayDisabled = disabled || limited;

  const classes = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('checked', checked),
    ns.is('indeterminate', indeterminate),
    ns.is('disabled', displayDisabled),
    ns.is('bordered', border),
    className,
  );

  return (
    <label className={classes} style={style}>
      <span className={ns.e('input')}>
        <input
          ref={setRef}
          className={ns.e('original')}
          type="checkbox"
          name={name}
          value={value}
          checked={checked}
          disabled={displayDisabled}
          aria-checked={indeterminate ? 'mixed' : checked}
          onChange={handleChange}
          {...rest}
        />
        <span className={ns.e('inner')} />
      </span>
      {(content !== undefined && content !== null) && (
        <span className={ns.e('label')}>{content}</span>
      )}
    </label>
  );
});

import {
  createContext,
  forwardRef,
  type HTMLAttributes,
  useCallback,
  useMemo,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';

export type CheckboxValueType = string | number;

export interface CheckboxGroupContextValue {
  /** Currently checked values. */
  value: CheckboxValueType[];
  /** Whether the given value is checked. */
  isChecked: (value: CheckboxValueType) => boolean;
  /** Toggle the given value, respecting `min`/`max`. */
  toggle: (value: CheckboxValueType) => void;
  /** Disable every descendant checkbox. */
  disabled: boolean;
  /** Size shared by descendant checkboxes. */
  size: ComponentSize;
  /** Minimum number of checked items. */
  min?: number;
  /** Maximum number of checked items. */
  max?: number;
}

export const CheckboxGroupContext = createContext<CheckboxGroupContextValue | null>(null);

export interface CheckboxGroupProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange' | 'defaultValue'> {
  /** Controlled checked values. */
  value?: CheckboxValueType[];
  /** Default checked values when uncontrolled. */
  defaultValue?: CheckboxValueType[];
  /** Fired when the checked values change. */
  onChange?: (value: CheckboxValueType[]) => void;
  /** Disable every checkbox in the group. */
  disabled?: boolean;
  /** Size shared by descendant checkboxes. */
  size?: ComponentSize;
  /** Minimum number of checked items. */
  min?: number;
  /** Maximum number of checked items. */
  max?: number;
}

export const CheckboxGroup = forwardRef<HTMLDivElement, CheckboxGroupProps>(function CheckboxGroup(
  props,
  ref,
) {
  const {
    value: valueProp,
    defaultValue,
    onChange,
    disabled: disabledProp,
    size: sizeProp,
    min,
    max,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('checkbox-group');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);

  const isControlled = valueProp !== undefined;
  const [internalValue, setInternalValue] = useState<CheckboxValueType[]>(defaultValue ?? []);
  const value = isControlled ? valueProp : internalValue;

  const isChecked = useCallback(
    (v: CheckboxValueType) => value.includes(v),
    [value],
  );

  const toggle = useCallback(
    (v: CheckboxValueType) => {
      const checked = value.includes(v);
      if (checked) {
        if (min !== undefined && value.length <= min) return;
      } else {
        if (max !== undefined && value.length >= max) return;
      }
      const next = checked ? value.filter((item) => item !== v) : [...value, v];
      if (!isControlled) setInternalValue(next);
      onChange?.(next);
    },
    [value, min, max, isControlled, onChange],
  );

  const ctx = useMemo<CheckboxGroupContextValue>(
    () => ({ value, isChecked, toggle, disabled, size, min, max }),
    [value, isChecked, toggle, disabled, size, min, max],
  );

  return (
    <CheckboxGroupContext.Provider value={ctx}>
      <div ref={ref} className={cls(ns.b(), className)} role="group" {...rest}>
        {children}
      </div>
    </CheckboxGroupContext.Provider>
  );
});

.ec-checkbox {
  --ec-checkbox-font-size: var(--ec-font-size-base);
  --ec-checkbox-font-weight: var(--ec-font-weight-primary);
  --ec-checkbox-text-color: var(--ec-text-color-regular);
  --ec-checkbox-input-size: 14px;
  --ec-checkbox-border-color: var(--ec-border-color);
  --ec-checkbox-bg-color: var(--ec-fill-color-blank);
  --ec-checkbox-checked-text-color: var(--ec-color-primary);
  --ec-checkbox-checked-bg-color: var(--ec-color-primary);
  --ec-checkbox-checked-border-color: var(--ec-color-primary);
  --ec-checkbox-disabled-border-color: var(--ec-border-color);
  --ec-checkbox-disabled-bg-color: var(--ec-fill-color-light);
  --ec-checkbox-disabled-text-color: var(--ec-disabled-text-color);
  --ec-checkbox-height: var(--ec-component-size);

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  height: var(--ec-checkbox-height);
  margin-right: 30px;
  font-size: var(--ec-checkbox-font-size);
  font-weight: var(--ec-checkbox-font-weight);
  color: var(--ec-checkbox-text-color);
  cursor: pointer;
  user-select: none;
  white-space: nowrap;
}

.ec-checkbox:last-of-type {
  margin-right: 0;
}

.ec-checkbox__input {
  position: relative;
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  line-height: 1;
  vertical-align: middle;
  white-space: nowrap;
  cursor: pointer;
}

/* Visually hidden native input for accessibility. */
.ec-checkbox__original {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  margin: 0;
  padding: 0;
  border: none;
  opacity: 0;
  outline: none;
  cursor: pointer;
  z-index: 1;
}

.ec-checkbox__original:disabled {
  cursor: not-allowed;
}

.ec-checkbox__inner {
  position: relative;
  display: inline-block;
  box-sizing: border-box;
  width: var(--ec-checkbox-input-size);
  height: var(--ec-checkbox-input-size);
  background-color: var(--ec-checkbox-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-checkbox-border-color);
  border-radius: var(--ec-border-radius-small);
  transition: var(--ec-transition-all);
}

/* Checkmark. */
.ec-checkbox__inner::after {
  content: '';
  position: absolute;
  top: 1px;
  left: 4px;
  box-sizing: content-box;
  width: 3px;
  height: 7px;
  border: 1px solid var(--ec-color-white);
  border-top: 0;
  border-left: 0;
  transform: rotate(45deg) scaleY(0);
  transform-origin: center;
  transition: transform 0.15s ease-in 0.05s;
}

.ec-checkbox__label {
  display: inline-block;
  padding-left: 8px;
  line-height: 1;
  font-size: var(--ec-checkbox-font-size);
}

/* ---- Hover ---- */
.ec-checkbox:not(.is-disabled):hover .ec-checkbox__inner {
  border-color: var(--ec-color-primary);
}

/* ---- Checked ---- */
.ec-checkbox.is-checked .ec-checkbox__inner {
  background-color: var(--ec-checkbox-checked-bg-color);
  border-color: var(--ec-checkbox-checked-border-color);
}

.ec-checkbox.is-checked .ec-checkbox__inner::after {
  transform: rotate(45deg) scaleY(1);
}

.ec-checkbox.is-checked .ec-checkbox__label {
  color: var(--ec-checkbox-checked-text-color);
}

/* ---- Indeterminate ---- */
.ec-checkbox.is-indeterminate .ec-checkbox__inner {
  background-color: var(--ec-checkbox-checked-bg-color);
  border-color: var(--ec-checkbox-checked-border-color);
}

.ec-checkbox.is-indeterminate .ec-checkbox__inner::after {
  top: 50%;
  left: 0;
  right: 0;
  width: auto;
  height: 0;
  margin: 0 2px;
  border: 0;
  border-top: 2px solid var(--ec-color-white);
  border-radius: 1px;
  transform: scaleY(1) translateY(-50%);
}

/* ---- Disabled ---- */
.ec-checkbox.is-disabled {
  color: var(--ec-checkbox-disabled-text-color);
  cursor: not-allowed;
}

.ec-checkbox.is-disabled .ec-checkbox__input,
.ec-checkbox.is-disabled .ec-checkbox__inner {
  cursor: not-allowed;
}

.ec-checkbox.is-disabled .ec-checkbox__inner {
  background-color: var(--ec-checkbox-disabled-bg-color);
  border-color: var(--ec-checkbox-disabled-border-color);
}

.ec-checkbox.is-disabled .ec-checkbox__inner::after {
  border-color: var(--ec-text-color-placeholder);
}

.ec-checkbox.is-disabled.is-indeterminate .ec-checkbox__inner::after {
  border-top-color: var(--ec-text-color-placeholder);
}

.ec-checkbox.is-disabled .ec-checkbox__label {
  color: var(--ec-checkbox-disabled-text-color);
}

/* ---- Bordered ---- */
.ec-checkbox.is-bordered {
  box-sizing: border-box;
  padding: 0 15px 0 9px;
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color);
  border-radius: var(--ec-border-radius-base);
  transition: var(--ec-transition-border);
}

.ec-checkbox.is-bordered.is-checked {
  border-color: var(--ec-color-primary);
}

.ec-checkbox.is-bordered.is-disabled {
  border-color: var(--ec-border-color-lighter);
}

/* ---- Sizes ---- */
.ec-checkbox--large {
  --ec-checkbox-height: var(--ec-component-size-large);
}
.ec-checkbox--large.is-bordered {
  padding: 0 19px 0 11px;
}

.ec-checkbox--small {
  --ec-checkbox-height: var(--ec-component-size-small);
  --ec-checkbox-font-size: var(--ec-font-size-small);
}
.ec-checkbox--small.is-bordered {
  padding: 0 11px 0 7px;
}
.ec-checkbox--small .ec-checkbox__inner {
  --ec-checkbox-input-size: 12px;
}
.ec-checkbox--small .ec-checkbox__inner::after {
  top: 0;
  left: 3px;
  height: 6px;
}

/* ---- Group ---- */
.ec-checkbox-group {
  display: inline-flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0 30px;
  font-size: 0;
}
.ec-checkbox-group .ec-checkbox {
  margin-right: 0;
}
